{
  "verses": [
    {
      "n": 45,
      "column": "left",
      "text": "Un wiꞥſch atmınnejahs\nwiꞥnu labbad ſawas Derribas/\nun tam bija ſchehſ pehz ſawas\nleelas Schehlaſtibas."
    },
    {
      "n": 46,
      "column": "left",
      "text": "Un parahdija teem Sirds-\nSchehlaſtibu preeſch wiſteem/\nkas tohs Žeetuna turreja."
    },
    {
      "n": 47,
      "column": "left",
      "text": "Atpeſti muhs KUNGGS/\nnuhsſu Deewſ / un fapulzina\nmuhs no teem Paganeem / ka\nmehs ſawam ſwehtam Wahr-\ndam pateizam/ un leelijamees ar\ntawu teizamnu Slawu."
    },
    {
      "n": 48,
      "column": "left",
      "text": "Slawehts lat irr tas\nKUNGGS/ Israëka Deews/\nmuhschigl muhschain/ un wiſi\nLaudis lai tahta: Amen / Alle-\nluja.\n"
    },
    {
      "n": 1,
      "column": "left",
      "text": "Ateizeet tam KUN-\nGA M / jo wiꞥſch irr\nlabs/ jo wiꞥnu Scheh-\nlaſtiba pateek muhschigt."
    },
    {
      "n": 2,
      "column": "left",
      "text": "Lai tee runna / fo tas\nKUNGGS irr atpeſtijs/ fo wiꞥſch\nno to Prettinceku Rohkas is-\nglahbis."
    },
    {
      "n": 3,
      "column": "left",
      "text": "Un no tahm Semnehm\nfapulzinajs/ no Rihta un Wah-\nkara Puﬀes/ no Seemeta Puﬀ-\nes/ un no Juhras."
    },
    {
      "n": 4,
      "column": "left",
      "text": "Tee/ kas Tukſneſi maldiſa"
    },
    {
      "n": 5,
      "column": "right",
      "text": "Isfalkufcht un iſſlahpuſ\nla wiꞥnu Dwehfele gann d\nnegurre."
    },
    {
      "n": 6,
      "column": "right",
      "text": "Un kad tee to KUNG\npeeſauze eekſch ſawahm B\ndahm/ un wiꞥſch tohs iſgla\nno ſawahm Isbailehm."
    },
    {
      "n": 7,
      "column": "right",
      "text": "Un waddija tohs us tai\nZeetu / ka tee gahje us tai\nPilsfahtu/ kur tee dsihwoht w\nreja."
    },
    {
      "n": 8,
      "column": "right",
      "text": "Teem buhs tam KUN\nGAM pateikt par wiꞥnu Sch-\nlaſtibu/ un var wiꞥnu Brih-\nmeem/ pee Zilweſu Rebrueem"
    },
    {
      "n": 9,
      "column": "right",
      "text": "Ka wiꞥſch to iſſlahpuſ\nDwehfeli pa-ehdinajs/ un to i\nſalkſchu Dwehfeli ar Labbum\npeeſildijs."
    },
    {
      "n": 10,
      "column": "right",
      "text": "Tee/ kas Tumſtbá fehd\nja um Nahweg Ehná / fatſitti\nSpaidischann un Dſelfehm."
    },
    {
      "n": 11,
      "column": "right",
      "text": "Par to/ ka tee ta STIP-\nRA DEEWA Bausleein pre-\ntiturreiſchees / un ta Wiſu-\naugſtaka Padohmu bij niizi-\nnajſchi."
    },
    {
      "n": 12,
      "column": "right",
      "text": "Kadeht wiꞥnu Sirds a\nBruhtunni apbehdinata tappe-\nun tee ſtratpaleja/ un Paliga n-\nbija."
    },
    {
      "n": 13,
      "column": "right",
      "text": "Kad tee to KUNGU pee-\nsauze eekſch ſawahm Behdahm/\nun wiꞥſch tohs no wiꞥnu Isbai-\nlehmn iſglahde."
    },
    {
      "n": 14,
      "column": "right",
      "text": "Un iſwedde tohs no tahs\nTumſbas un Nahweg Ehnaſ/\nun"
    }
  ],
  "confidence": "high",
  "notes": ""
}
